1;s:11:\"gdrive_link\";i:12;s:8:\"media_id\";i:13;s:18:\"venue_map_media_id\";i:14;s:12:\"is_published\";i:15;s:12:\"rsvp_enabled\";i:16;s:13:\"rsvp_deadline\";i:17;s:13:\"max_attendees\";i:18;s:16:\"require_approval\";i:19;s:9:\"meta_json\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}i:5;O:16:\"App\\Models\\Event\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:6:\"events\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:23:{s:2:\"id\";i:4;s:5:\"title\";s:30:\"Takaful4All Sustainability Day\";s:4:\"slug\";s:30:\"takaful4all-sustainability-day\";s:7:\"excerpt\";s:296:\"The Malaysian Takaful Association (MTA) is looking forward to meet you at the Takafu4Alll Sustainability Day 2024, themed “Protect, Care, Sustain”. This event is part of the Hijrah 27 Working Group 4 initiative which is championing the Takaful Industry’s ESG and Sustainability initiatives.\";s:12:\"content_html\";s:2388:\"<p>The Malaysian Takaful Association (MTA) is looking forward to meet you at the <strong>Takafu4Alll Sustainability Day 2024</strong>, themed<strong>&nbsp;“Protect, Care, Sustain”</strong>. This event is part of the <strong>Hijrah 27 Working Group 4</strong>&nbsp;initiative which is championing the Takaful Industry’s ESG and Sustainability initiatives.&nbsp;</p><p>Our vision is simple but yet powerful: to inspire everyone, especially the younger generation, to adopt sustainable practices and environmental conservation in their daily lives. This fun-filled day promises something for everyone which will feature interactive and hands-on activities designed to connect everyone with nature whilst promoting good health, fostering a deeper understanding and commitment to sustainability.&nbsp;</p><p>Highlights of the events:</p><ul><li><p><strong>Larian Hero Hijau</strong>: A refreshing 5 kilo meter morning fun-run at perimeter of Taman Tugu to kickstart the day.</p></li><li><p><strong>Zero Waste Lifestyle Workshop</strong>: Learn practical steps toward sustainable living with Zero Waste Malaysia.</p></li><li><p><strong>Launch of Takaful4All Disaster Response Team</strong>: Witness the unveiling of this impactful initiative by Takaful Industry in expanding its Disaster Response Team – don’t miss the chance to register for the Takaful Disaster Taskforce, which is co-organized with Jabatan Bomba dan Penyelamat Malaysia.</p></li><li><p><strong>Sustainability Carnival</strong>: Engage in eco-friendly workshops, art, photography, and financial &amp; sustainability literacy activities.</p></li><li><p><strong>Folks Sport Activities:</strong>&nbsp;Relive your childhood memories through “Timbang Bulu Ayam” and “Musang Berjanggut” games to bring back the good old days</p></li><li><p><strong>Coloring Contest:</strong>&nbsp;Educating the children on preserving nature for sustainability&nbsp;</p></li><li><p><strong>Takaful Sustainability Booth:</strong>&nbsp;Showcase of Sustainability activities or Takaful Products by 15 Takaful Operators</p></li></ul><p>We would love for this event to be a day of fun, learning, and connection—not just for you but also for your teams, families, and friends. We kindly ask for your support in spreading the word by sharing this invitation across your organisation to ensure everyone has the opportunity to join us.</p>\";s:8:\"start_at\";s:19:\"2024-12-15 12:14:00\";s:6:\"end_at\";s:19:\"2024-12-15 17:14:00\";s:5:\"venue\";s:18:\"Taman Tugu Nursery\";s:4:\"city\";s:12:\"Kuala Lumpur\";s:5:\"state\";s:19:\"Wilayah Persekutuan\";s:7:\"country\";s:8:\"Malaysia\";s:16:\"registration_url\";N;s:11:\"gdrive_link\";N;s:8:\"media_id\";i:30;s:18:\"venue_map_media_id\";N;s:12:\"is_published\";i:1;s:12:\"rsvp_enabled\";i:0;s:13:\"rsvp_deadline\";N;s:13:\"max_attendees\";N;s:16:\"require_approval\";i:0;s:9:\"meta_json\";N;s:10:\"created_at\";s:19:\"2026-02-24 12:14:37\";s:10:\"updated_at\";s:19:\"2026-02-24 16:14:21\";}s:11:\"\0*\0original\";a:23:{s:2:\"id\";i:4;s:5:\"title\";s:30:\"Takaful4All Sustainability Day\";s:4:\"slug\";s:30:\"takaful4all-sustainability-day\";s:7:\"excerpt\";s:296:\"The Malaysian Takaful Association (MTA) is looking forward to meet you at the Takafu4Alll Sustainability Day 2024, themed “Protect, Care, Sustain”. This event is part of the Hijrah 27 Working Group 4 initiative which is championing the Takaful Industry’s ESG and Sustainability initiatives.\";s:12:\"content_html\";s:2388:\"<p>The Malaysian Takaful Association (MTA) is looking forward to meet you at the <strong>Takafu4Alll Sustainability Day 2024</strong>, themed<strong>&nbsp;“Protect, Care, Sustain”</strong>. This event is part of the <strong>Hijrah 27 Working Group 4</strong>&nbsp;initiative which is championing the Takaful Industry’s ESG and Sustainability initiatives.&nbsp;</p><p>Our vision is simple but yet powerful: to inspire everyone, especially the younger generation, to adopt sustainable practices and environmental conservation in their daily lives. This fun-filled day promises something for everyone which will feature interactive and hands-on activities designed to connect everyone with nature whilst promoting good health, fostering a deeper understanding and commitment to sustainability.&nbsp;</p><p>Highlights of the events:</p><ul><li><p><strong>Larian Hero Hijau</strong>: A refreshing 5 kilo meter morning fun-run at perimeter of Taman Tugu to kickstart the day.</p></li><li><p><strong>Zero Waste Lifestyle Workshop</strong>: Learn practical steps toward sustainable living with Zero Waste Malaysia.</p></li><li><p><strong>Launch of Takaful4All Disaster Response Team</strong>: Witness the unveiling of this impactful initiative by Takaful Industry in expanding its Disaster Response Team – don’t miss the chance to register for the Takaful Disaster Taskforce, which is co-organized with Jabatan Bomba dan Penyelamat Malaysia.</p></li><li><p><strong>Sustainability Carnival</strong>: Engage in eco-friendly workshops, art, photography, and financial &amp; sustainability literacy activities.</p></li><li><p><strong>Folks Sport Activities:</strong>&nbsp;Relive your childhood memories through “Timbang Bulu Ayam” and “Musang Berjanggut” games to bring back the good old days</p></li><li><p><strong>Coloring Contest:</strong>&nbsp;Educating the children on preserving nature for sustainability&nbsp;</p></li><li><p><strong>Takaful Sustainability Booth:</strong>&nbsp;Showcase of Sustainability activities or Takaful Products by 15 Takaful Operators</p></li></ul><p>We would love for this event to be a day of fun, learning, and connection—not just for you but also for your teams, families, and friends. We kindly ask for your support in spreading the word by sharing this invitation across your organisation to ensure everyone has the opportunity to join us.</p>\";s:8:\"start_at\";s:19:\"2024-12-15 12:14:00\";s:6:\"end_at\";s:19:\"2024-12-15 17:14:00\";s:5:\"venue\";s:18:\"Taman Tugu Nursery\";s:4:\"city\";s:12:\"Kuala Lumpur\";s:5:\"state\";s:19:\"Wilayah Persekutuan\";s:7:\"country\";s:8:\"Malaysia\";s:16:\"registration_url\";N;s:11:\"gdrive_link\";N;s:8:\"media_id\";i:30;s:18:\"venue_map_media_id\";N;s:12:\"is_published\";i:1;s:12:\"rsvp_enabled\";i:0;s:13:\"rsvp_deadline\";N;s:13:\"max_attendees\";N;s:16:\"require_approval\";i:0;s:9:\"meta_json\";N;s:10:\"created_at\";s:19:\"2026-02-24 12:14:37\";s:10:\"updated_at\";s:19:\"2026-02-24 16:14:21\";}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:8:{s:8:\"start_at\";s:8:\"datetime\";s:6:\"end_at\";s:8:\"datetime\";s:12:\"is_published\";s:7:\"boolean\";s:12:\"rsvp_enabled\";s:7:\"boolean\";s:13:\"rsvp_deadline\";s:8:\"datetime\";s:13:\"max_attendees\";s:7:\"integer\";s:16:\"require_approval\";s:7:\"boolean\";s:9:\"meta_json\";s: