INSERT INTO `pages` VALUES (1,'About Us','about','<section><h2>About the Malaysian Takaful Association</h2><p>The <strong>Malaysian Takaful Association (MTA)</strong> is the national trade association representing the takaful (Islamic insurance) industry in Malaysia. Established to promote the growth, development, and awareness of the takaful industry, MTA serves as the unified voice for all takaful operators in the country.</p><p>With a membership comprising all licensed takaful operators in Malaysia, MTA works closely with regulatory bodies such as <strong>Bank Negara Malaysia (BNM)</strong> and the Ministry of Finance to shape policy and create a conducive environment for the takaful sector to flourish.</p></section>',NULL,1,'2026-02-24 04:14:37','2026-02-24 04:14:37'),(2,'Contact Us','contact','<section><h2>Get in Touch</h2><p>We welcome enquiries from industry stakeholders, media, and the public.</p><p><strong>Malaysian Takaful Association</strong><br>Level 29, Menara Takaful Malaysia<br>No. 4, Jalan Sultan Sulaiman<br>50000 Kuala Lumpur, Malaysia</p><p>Email: <a href=\"mailto:info@malaysiantakaful.com.my\">info@malaysiantakaful.com.my</a><br>Tel: +603 2031 8084</p></section>',NULL,1,'2026-02-24 04:14:37','2026-02-24 04:14:37'),(3,'Terms & Conditions','terms-conditions','<section>\n<p>Welcome to events.takaful4all.org for online event registration. Terms and conditions stated below applies to all visitors and users of events.takaful4all.org. You are bound by these terms and conditions if you\'re on events.takaful4all.org.</p>\n\n<h2>General</h2>\n<p>The content of terms and conditions may be change, move, or delete at any time. Please note that events.takaful4all.org have the rights to change the contents of the terms and conditions without any notice. Any violation of rules and regulations of these terms and conditions, events.takaful4all.org will take immediate actions against the offender(s).</p>\n\n<h2>Site Contents &amp; Copyrights</h2>\n<p>Unless otherwise noted, all materials, including images, illustrations, designs, icons, photographs, video clips, and written and other materials that appear as part of this Site, in other words \"Contents of the Site\" are copyrights, trademarks, trade dress and/or other intellectual properties owned, controlled, or licensed by Persatuan Takaful Malaysia (Takaful4all).</p>\n\n<h2>Comments and Feedbacks</h2>\n<p>All comments and feedbacks to Persatuan Takaful Malaysia (Takaful4all) will be remain at <a href=\"mailto:enquiries@malaysiantakaful.com.my\">enquiries@malaysiantakaful.com.my</a>. User shall agree that there will be no comment(s) submitted to the events.takaful4all.org will violate any rights of any third party, including copyrights, trademarks, privacy of other personal or proprietary right(s). Furthermore, the user shall agree there will not be content of unlawful, abusive, or obscene material(s) submitted to the site. User will be the only one responsible for any comment\'s content made.</p>\n\n<h2>Product Information</h2>\n<p>We cannot guarantee all actual products will be the same shown on the monitor as that is depending on the user monitor.</p>\n\n<h2>Newsletter</h2>\n<p>User shall agree that events.takaful4all.org may send newsletter regarding the latest news/products/promotions etc through email to the user.</p>\n\n<h2>Indemnification</h2>\n<p>The user shall agree to defend, indemnify, and hold Takaful4all.org harmless from and against any and all claims, damages, costs and expenses, including attorneys\' fees, arising from or related to your use of the Site.</p>\n\n<h2>Link to Other Sites</h2>\n<p>Any access link to third party sites is at your own risk. events.takaful4all.org will not be related or involved in any such website if the user\'s content/product(s) got damaged or loss have any connection with a third party site.</p>\n\n<h2>Inaccuracy Information</h2>\n<p>From time to time, there may be information on events.takaful4all.org that contains typographical error, inaccuracies, omissions, that may relate to product description, pricing, availability, and article contents. We reserve the rights to correct any errors, inaccuracies, change or edit information without prior notice to the customers. If you are not satisfied with your purchased product(s), please return it back to us with the invoice.</p>\n\n<h2>Termination</h2>\n<p>This agreement is effective unless and until either by the customer or events.takaful4all.org. Customer may terminate this agreement at any time. However, events.takaful4all.org may also terminate the agreement with the customer without any prior notice and will be denying the access of the customer who is unable to comply the terms and conditions above.</p>\n\n<h2>Refund Policy</h2>\n<p>Your full refund will be issued once we have received and examined the returned goods at our return center.</p>\n\n<h2>Shipping and Delivery Policy</h2>\n<ul>\n<li>Items in stock: 2–5 working days for Standard Delivery items.</li>\n<li>Items that are out of stock: Please email or call us for assistance.</li>\n</ul>\n\n<h2>Payments</h2>\n<p>All Goods purchased are subject to a one-time payment. Payment can be made through various payment methods we have available, such as Visa, MasterCard or online payment methods. Payment cards (credit cards or debit cards) are subject to validation checks and authorization by your card issuer. If we do not receive the required authorization, we will not be liable for any delay or non-delivery of your Order.</p>\n</section>',NULL,1,'2026-02-24 04:14:37','2026-02-24 08:18:45'),(4,'Privacy Policy','privacy-policy','<section><h2>Privacy Policy</h2><p>The Malaysian Takaful Association is committed to protecting the privacy of your personal data in accordance with the <strong>Personal Data Protection Act 2010 (PDPA)</strong>.</p><h3>Data We Collect</h3><p>We may collect personal information such as your name, email address, and phone number when you register for events or contact us.</p><h3>How We Use Your Data</h3><p>Your data is used solely for event registration, communications related to MTA activities, and improving our services.</p></section>',NULL,1,'2026-02-24 04:14:37','2026-02-26 09:21:21'),(5,'Cancellation & Refund Policy','cancellation-refund-policy','<p><strong>CANCELLATION POLICY</strong></p><p><strong>Cancellation Prior to Order Processing</strong> If you cancel your registration before it is processed, you will not be charged any additional fees. We require a cancellation request to be submitted by emailing us at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-brand underline\" href=\"mailto:enquiries@malaysiantakaful.com.my\">enquiries@malaysiantakaful.com.my</a>. Once the cancellation request is received, a full refund will be initiated. We advise submitting a cancellation request within 12 hours of your registration submission.</p><p><strong>RETURN POLICY</strong> The following policies apply to be eligible for return requests after the registration is completed:</p><p>Registrations fees are returnable within 7 working days starting from the day the registration is confirmed if they are incorrect, or if the event is canceled or postponed.</p><p>Only tickets or registration fees purchased directly from <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-brand underline\" href=\"http://events.takaful4all.org\">events.takaful4all.org</a> are eligible for return. Any <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-brand underline\" href=\"http://events.takaful4all.org\">events.takaful4all.org</a> product purchased through other retailers must adhere to the respective retailers’ returns and refunds policy. Tickets or registration fees are eligible for a return if the following conditions are met:</p><p><strong>Incorrect Registrations:</strong> The registration details do not match what was ordered, or there are errors in the registration information provided.</p><p><strong>Event Cancellations or Postponements:</strong> The event for which the ticket or registration was made is canceled or postponed.</p><p><strong>Return Requirements:</strong></p><ul><li><p>The cancellation request must be submitted within 7 working days upon receipt of the registration confirmation.</p></li><li><p>You have proof of purchase (order invoice number and receipt).</p></li></ul><p>Change of registration and cancellation of registration will not be permitted once payment has been confirmed.</p><p>Any cancellations due to a change of mind will not be accepted. We reserve the right to reject any cancellation or refund request that is deemed unfit or unreasonable.</p><p><strong>REFUND POLICY</strong></p><p>Your full refund will be issued once we have received and examined the cancellation request at our return center. Once the cancellation request fulfills our return policy, the full refund will be initiated. The method of refund will be processed depending on your original payment method:</p><p><strong>Online Bank Transfer:</strong> Full refunds will be credited into your bank account via online bank transfer, which should be posted within 3-5 working days.</p><p><strong>Credit Card Refunds:</strong> Refunds will be sent to the card-issuing bank. Kindly contact your card-issuing bank regarding the duration of the credit refunds.</p>',NULL,1,'2026-02-24 04:14:37','2026-02-24 08:36:01'),(6,'Terms & Conditions','terms','<section>\n<p>Welcome to events.takaful4all.org for online event registration. Terms and conditions stated below applies to all visitors and users of events.takaful4all.org. You are bound by these terms and conditions if you\'re on events.takaful4all.org.</p>\n\n<h2>General</h2>\n<p>The content of terms and conditions may be change, move, or delete at any time. Please note that events.takaful4all.org have the rights to change the contents of the terms and conditions without any notice. Any violation of rules and regulations of these terms and conditions, events.takaful4all.org will take immediate actions against the offender(s).</p>\n\n<h2>Site Contents &amp; Copyrights</h2>\n<p>Unless otherwise noted, all materials, including images, illustrations, designs, icons, photographs, video clips, and written and other materials that appear as part of this Site, in other words \"Contents of the Site\" are copyrights, trademarks, trade dress and/or other intellectual properties owned, controlled, or licensed by Persatuan Takaful Malaysia (Takaful4all).</p>\n\n<h2>Comments and Feedbacks</h2>\n<p>All comments and feedbacks to Persatuan Takaful Malaysia (Takaful4all) will be remain at <a href=\"mailto:enquiries@malaysiantakaful.com.my\">enquiries@malaysiantakaful.com.my</a>. User shall agree that there will be no comment(s) submitted to the events.takaful4all.org will violate any rights of any third party, including copyrights, trademarks, privacy of other personal or proprietary right(s). Furthermore, the user shall agree there will not be content of unlawful, abusive, or obscene material(s) submitted to the site. User will be the only one responsible for any comment\'s content made.</p>\n\n<h2>Product Information</h2>\n<p>We cannot guarantee all actual products will be the same shown on the monitor as that is depending on the user monitor.</p>\n\n<h2>Newsletter</h2>\n<p>User shall agree that events.takaful4all.org may send newsletter regarding the latest news/products/promotions etc through email to the user.</p>\n\n<h2>Indemnification</h2>\n<p>The user shall agree to defend, indemnify, and hold Takaful4all.org harmless from and against any and all claims, damages, costs and expenses, including attorneys\' fees, arising from or related to your use of the Site.</p>\n\n<h2>Link to Other Sites</h2>\n<p>Any access link to third party sites is at your own risk. events.takaful4all.org will not be related or involved in any such website if the user\'s content/product(s) got damaged or loss have any connection with a third party site.</p>\n\n<h2>Inaccuracy Information</h2>\n<p>From time to time, there may be information on events.takaful4all.org that contains typographical error, inaccuracies, omissions, that may relate to product description, pricing, availability, and article contents. We reserve the rights to correct any errors, inaccuracies, change or edit information without prior notice to the customers. If you are not satisfied with your purchased product(s), please return it back to us with the invoice.</p>\n\n<h2>Termination</h2>\n<p>This agreement is effective unless and until either by the customer or events.takaful4all.org. Customer may terminate this agreement at any time. However, events.takaful4all.org may also terminate the agreement with the customer without any prior notice and will be denying the access of the customer who is unable to comply the terms and conditions above.</p>\n\n<h2>Refund Policy</h2>\n<p>Your full refund will be issued once we have received and examined the returned goods at our return center.</p>\n\n<h2>Shipping and Delivery Policy</h2>\n<ul>\n<li>Items in stock: 2–5 working days for Standard Delivery items.</li>\n<li>Items that are out of stock: Please email or call us for assistance.</li>\n</ul>\n\n<h2>Payments</h2>\n<p>All Goods purchased are subject to a one-time payment. Payment can be made through various payment methods we have available, such as Visa, MasterCard or online payment methods. Payment cards (credit cards or debit cards) are subject to validation checks and authorization by your card issuer. If we do not receive the required authorization, we will not be liable for any delay or non-delivery of your Order.</p>\n</section>',NULL,1,'2026-02-26 09:21:21','2026-02-26 09:21:21'),(7,'Cancellation & Refund Policy','cancellation-refund','<section><h2>Cancellation & Refund Policy</h2><p>We understand that plans can change. Please review our cancellation and refund policy below.</p><h3>Event Registration Cancellations</h3><ul><li><strong>More than 14 days before the event:</strong> Full refund minus a 10% administrative fee.</li><li><strong>7–14 days before the event:</strong> 50% refund.</li><li><strong>Less than 7 days before the event:</strong> No refund. Substitutions are permitted.</li></ul><h3>How to Cancel</h3><p>Please contact us at <a href=\"mailto:events@malaysiantakaful.com.my\">events@malaysiantakaful.com.my</a> with your registration details.</p></section>',NULL,1,'2026-02-26 09:21:21','2026-02-26 09:21:21');
